{
  "name": "Illinois PACE (Program of All-Inclusive Care for the Elderly)",
  "eligibility": {
    "age": 55,
    "income_limits": "No specific income limits for PACE enrollment itself; eligibility is not based on financial criteria. However, for full coverage at no cost (covering 90-99% of participants who are dual-eligible), Medicaid eligibility is typically required, which follows Illinois long-term care rules: income under 300% of Federal Benefit Rate ($2,901/month for 2025, single person; varies by household size—check current HFS Medicaid tables). Private pay or share of cost ($200-$900/month) possible if over limits.[2][6]",
    "asset_limits": "No asset limits for PACE enrollment. For Medicaid (dual-eligibility), assets $2,000 or less for single (excluding primary home, one vehicle, burial plots). Medicaid planning available to qualify.[2][6]",
    "other_requirements": [
      "Live in the service area of an Illinois PACE organization (specific zip codes in 5 regions: West Chicago, South Chicago, Southern Cook County, Peoria, East St. Louis).",
      "Certified by Illinois as needing nursing home level of care (frail elderly, requiring extensive assistance with ADLs, but able to live safely in community with PACE support).",
      "Voluntary enrollment; not in Medicare Advantage, hospice, or certain other programs."
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive, all-inclusive care 24/7/365: primary care clinic at PACE center, therapeutic recreation, restorative therapies, socialization, personal care, dining, home care, inpatient (acute/long-term when needed), prescription drugs, transportation. Covers all Medicare/Medicaid services; sole source for enrollees. No specific dollar amounts or hours stated—customized per participant via interdisciplinary team.[1][3][7]",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Search by zip code on HFS site or contact local PACE provider (e.g., OSF PACE).",
      "Phone: Contact Illinois Department of Healthcare and Family Services (HFS) at 1-877-582-9701 (general Medicaid) or specific providers like OSF PACE.",
      "In-person: At PACE centers in designated regions.",
      "Website: hfs.illinois.gov/medicalproviders/pace.html for zip code search and provider list."
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Possible; varies by region/provider—not detailed.",
    "forms": ["No specific form name/number listed; initial assessment by PACE organization and state certification for nursing home level of care."],
    "documents": [
      "Proof of age/residency, medical records for nursing home level assessment, Medicare/Medicaid cards (if applicable), income/asset info for Medicaid (if seeking dual-eligibility)."
    ]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to specific zip codes in 5 regions: West Chicago, South Chicago, Southern Cook County, Peoria, East St. Louis. Detailed zip list on HFS site.",
    "regional_variations": "Different PACE organizations/providers per region (e.g., OSF PACE in Peoria area); potential differences in wait times, capacity, services emphasis.",
    "offices_or_providers": [
      "West Chicago, South Chicago, Southern Cook County, Peoria (e.g., OSF PACE), East St. Louis."
    ]
  },
  "official_source": "https://hfs.illinois.gov/medicalproviders/pace.html",
  "gotchas": [
    "Not statewide—must live in exact service area zip code; check first.",
    "Replaces all Medicare/Medicaid; cannot stay on regular plans or Medicare Advantage/hospice.",
    "Nursing home certification required but must be community-safe with PACE—no financial eligibility for entry, but Medicaid needed for free full coverage.",
    "Private pay expensive ($7,000+/month) if not dual-eligible.",
    "Voluntary; can disenroll anytime, but coordinated team manages all care."
  ],
  "data_shape_notes": "Limited to 5 specific regions with zip code restrictions; no direct income/asset test for PACE but Medicaid financials for no-cost access; provider-specific variations."
}

{
  "name": "Senior Health Insurance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries and their caregivers.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Must be a Medicare beneficiary (typically age 65+ or qualifying disabled under Medicare)", "Caregivers or family assisting Medicare-eligible individuals also qualify for counseling"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, unbiased, personalized health insurance counseling including: education on Medicare (Parts A-D), Medicare supplements, Medicare Part D, Medicare Advantage, long-term care insurance; assistance with enrollment in Part D and extra financial help for Part B/D premiums; help filing claims, analyzing policies, resolving billing issues and appeals; community education seminars.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-800-252-8966 (statewide, connects to local counselor)", "Email: aging.ship@illinois.gov", "Website: https://ilaging.illinois.gov/ship.html (find local sites and resources)", "Local in-person or phone via regional providers (e.g., Ford County: 217-379-9281; CEFS: 217-342-2193 ext 2135; Skokie: 847-933-8252)"],
    "processing_time": "Immediate counseling available by phone; appointments for in-person vary by local site (e.g., year-round in Skokie)",
    "waitlist": null,
    "forms": ["No specific application forms required; counselors assist directly with Medicare-related forms during sessions"],
    "documents": ["Medicare card, current insurance policies/statements, billing/claims notices if issues exist (optional, provided as needed for counseling)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available across all Illinois counties",
    "regional_variations": "Delivered through local counselors and organizations (e.g., county health departments, economic opportunity corps, community centers); contact methods and appointment availability vary by region but services standardized statewide.",
    "offices_or_providers": ["State office: One Natural Resources Way, Suite 100, Springfield IL 62702", "Local examples: Ford County PHD, CEFS Economic Opportunity Corporation, Skokie Human Services"]
  },
  "official_source": "https://ilaging.illinois.gov/ship.html",
  "gotchas": ["Not an insurance provider or seller—counselors do not sell policies or represent insurers.", "Free service, no enrollment into SHIP itself; it's counseling access.", "Targeted at Medicare navigation, not direct medical care or financial aid.", "During Medicare Open Enrollment (Oct 15-Dec 7), prioritize plan comparisons."],
  "data_shape_notes": "no income/asset test; counseling-only advocacy service via statewide network of local providers; eligibility purely Medicare-based"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; available regardless of financial status[1][4][5]",
    "asset_limits": "No asset limits; no financial requirements[5]",
    "other_requirements": ["Current, prospective, or former resident (age 60+) of a long-term care facility (e.g., nursing homes, assisted living); friends/relatives of residents; facility staff/administrators with resident concerns; individuals/families considering placement; community at large[1][4]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy to resolve complaints (e.g., neglect, abuse, rights violations); investigation of concerns; education on resident rights, long-term care options, and services; promotion of quality of life and care; facilitation of family councils; routine facility visits; assistance to facility staff; intervention in private homes/community settings for older persons/disabilities[1][2][4][5][7][8]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Senior HelpLine 1-800-252-8966 (press 1), TTY 1-888-206-1327 or 711[6][8][9]", "Local/regional ombudsman programs (contact via Senior HelpLine for specifics)[6]", "Mail: Long-Term Care Ombudsman Program, Illinois Department on Aging, One Natural Resources Way, Suite 100, Springfield, IL 62702-1271[6][9]", "Email: To Illinois Department on Aging[9]", "Regional examples: DuPage County - Call 630-407-6500, 211, text zip code to 898211, or visit www.dupagecounty.gov/community[5]"],
    "processing_time": "Immediate assistance for complaints/concerns; no formal processing time specified[1][4]",
    "waitlist": null,
    "forms": ["No specific application forms required for receiving services; designation applications for regional programs only[3]"],
    "documents": ["No documents needed; contact directly for assistance[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services tied to long-term care facilities statewide; expanded to private homes/community settings[2]",
    "regional_variations": "Administered through Office of State Long Term Care Ombudsman with designated regional programs; each region has its own ombudsman coordinators, visit schedules, and contact points; e.g., DuPage County has local phone/options[2][3][5][6]",
    "offices_or_providers": ["Regional Long-Term Care Ombudsman Programs designated by state office; contact Senior HelpLine for local office[2][3][6]"]
  },
  "official_source": "https://ilaging.illinois.gov (Illinois Department on Aging)",
  "gotchas": ["Not a healthcare or financial benefits program—purely advocacy and complaint resolution[1][7][9]", "Primarily for long-term care facility residents (age 60+); expanded but focus remains facilities[2][4]", "Anyone can contact (no eligibility barriers), but services resolve issues, not provide direct care[1][4][5]", "Regional programs handle local delivery; must contact local ombudsman for facility-specific help[2][3][6]", "Volunteers undergo training/background checks, but residents/families just call for help[6]"],
  "data_shape_notes": "no income test; statewide with regional delivery; advocacy-only, open to residents/families/staff/community without financial or document barriers"
}

{
  "name": "Benefit Access Program (Seniors Ride Free & License Plate Discount)",
  "eligibility": {
    "age": "65 or older before January 1 of the current year, or turning 65 this year (benefits available after turning 65), or 16 or older and disabled[3][5][7]",
    "income_limits": "$33,562 for 1-person household; $44,533 for 2-person household (self + spouse or 1 Qualified Additional Resident); $55,500 for 3-person household (self + spouse + 1 QAR or self + 2 QAR). Total gross income from last closed tax year. Include spouse's income if married and living together on Dec 31 of last year; exclude QAR income[3][7]",
    "asset_limits": "No asset limits mentioned[1][2][3][7]",
    "other_requirements": ["Illinois resident at time of application[5]", "Valid Social Security number required (spouse and QAR also need SSN if applicable)[1][2][7]", "U.S. citizenship not required[7]"]
  },
  "benefits": {
    "type": "in_kind",
    "value": "License plate fee discount of $75 on one vehicle per household (specific plate types eligible; wait 10 business days post-approval to use). Ride Free Permit ID card for free rides on fixed-route CTA, Metra (RTA), and Pace buses/trains (local transit may have additional requirements)[1][3][4][5]",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Online: https://ilaging.illinois.gov/benefitsaccess.html[2][3][4]", "Assistance via local AgeGuide or agencies like Bacoa (e.g., 847-381-5030)[1][2]", "Phone for license plate questions: 1-800-252-8980[4]", "In-person: Local transit authority or Secretary of State office with printed certificate post-approval[3]"],
    "processing_time": "Up to 8 weeks depending on documentation; check status after 48 hours; license plate discount active after 10 business days post-approval[3]",
    "waitlist": null,
    "forms": ["Benefit Access Online Application (no specific form number; accessed via ilaging.illinois.gov/benefitsaccess.html)[2][3][4]"],
    "documents": ["Proof of income", "Social Security number", "Spouse's SSN and DOB if married and living together", "Print certificate of eligibility post-approval for transit/SOS office[1][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Illinois residents only[5]",
    "regional_variations": "Local public transit systems may have additional requirements for Ride Free Permit usage[3]",
    "offices_or_providers": ["Local transit authority for Ride Free details", "Secretary of State's office for license plate discount (1-800-252-8980)[3][4]"]
  },
  "official_source": "https://ilaging.illinois.gov/benefitsaccess.html[3]",
  "gotchas": ["Only one license plate discount per household per year, for one vehicle titled to the applicant[1][4]", "Must wait 10 business days post-approval for license plate discount to activate[3][4][5]", "Benefits for those turning 65 available only after birthday[3][5]", "Local transit may require extra steps for free rides[3]", "Spouse must have SSN; include spouse income if living together Dec 31[1][7]", "No discount for multiple vehicles[4]"],
  "data_shape_notes": "Income-tested with fixed household size tiers up to 3 persons; no asset test; statewide but local transit variations; one vehicle limit per household"
}
